# Classificação de índice de qualidade do ar (IQA)
iqua = float(input("Índice de qualidade do ar: "))

if iqua <= 40:
    classificacao = "Boa"
elif iqua <= 80:
    classificacao = "Moderada"
elif iqua <= 120:
    classificacao = "Ruim para grupos sensíveis"
elif iqua <= 200:
    classificacao = "Ruim"
else:
    classificacao = "Muito Ruim / Perigosa"

print(f"IQA: {iqua} — Qualidade: {classificacao}")

