# Classificador de risco de desmatamento (dados INPE)
percentual_cobertura = float(input("Cobertura florestal restante (%): "))

if percentual_cobertura >= 80:
    risco = "BAIXO"
elif percentual_cobertura >= 60:
    risco = "MODERADO"
elif percentual_cobertura >= 40:
    risco = "ALTO"
else:
    risco = "CRITICO — EMERGÊNCIA AMBIENTAL"

print(f"Cobertura: {percentual_cobertura:.1f}%")
print(f"Nível de risco: {risco}")
